// Sign document with pdf format
// Author: ĐHV 04/04/2025
(function ($) {
    const defaults = {
        loadSigndocPath: null,
    };
    const ON_DOC_LOADED = "docloaded";
    const ON_SIGN = "dosign";
    const ON_REMOVE_SIGN = "removesign";
    
    const pdfSign = function (mainId, options) {
        this.pdfContainer = $(mainId);
        this.signTempElement = null; // div.#sign-temp-element
        this.pageState = null; // div.#page-state
        this.pageList = null; // div.#page-list

        this.options = $.extend({}, defaults, options);
        
        this.bMouseDown = false;
        this.bMouseMove = false;
        this.bMouseScale = false;
        this.offset;
        this.mousePositionedit;
        this.mousePositionAdd;
        this.currentEditElement;
        this.signData = null;
        this.pageRenderList = [];
        this.pageCount = 0;
        this.previewelement = null;
        this.mainContainer = null;
        this.jwindow = null;
        this.aspectRatio;
        this.currentSigDocId = null;
        this.currentSelectPage = 1;
        this.default_scale = 1.3333333333333333;
        this.events = {};
        this.bSignExist = false;
    }

    pdfSign.prototype = {
        init: function() {
            this.initElement();
            this.initEvents();

            return {
                setUserSign: (sign) => this.setUserSign(sign),
                loadSigndocById: (id,bPreview) => this.loadSigndocById(id,bPreview),
                doSign: () => this.doSign(),
                setSignStatus: (bSign) => this.setSignStatus(bSign),
                getData: () => this.getSignData(),
                on: (eventName,callback)=>{ this.on(eventName,callback)}
            }
        },

        initElement: function(){
            let wrap = $(`<div class="d-flex align-items-center justify-content-center" style="position: relative;"></div>`);
            
            this.pageState = $(`<div id="page-state" class="page-state hidden-style"> Trang 1</div>`);
            this.pageList = $(`<div id="page-list" class="pdf-page-list hidden-style"></div>`);
            this.pageList.on('scroll',()=>{
                this.onPagesScroll();
            });
            this.signTempElement = $(`<div style="display:none;" class="d-none"></div>`);
            
            wrap.append(this.pageState);
            wrap.append(this.pageList);
            this.pdfContainer.append(wrap);
            this.pdfContainer.append(this.signTempElement);

            // loading
            this.pdfContainer.append(`
                    <div style="display:flex;justify-content: center;flex-direction: column;align-items: center;" class="p-2 pdf-loading">
                        <div class="spinner-border" role="status"></div>
                        <p class="m-0 p-0">Đang tải dữ liệu ...</p>
                    </div>
                `);
        },

        initEvents: function (){
            this.pdfContainer.on('mousemove touchmove',(event)=>{
                this.onMousemoveContainer(event);
            });

            this.pdfContainer.on('mousedown touchstart',(event)=>{
                this.onPdfContainerMouseDown(event);
            });
            
            this.pdfContainer.on('mouseleave touchcancel',(event)=>{
                this.onPdfContainerMouseLeave(event);
            });

            this.pdfContainer.on('mouseup touchend',(event)=>{
                this.onPdfContainerMouseUp(event);
            });


            this.pageList.on( 'scroll', function(){
                const children = document.querySelectorAll('.pdf-page-wrap');
                const parentHeight = parent.clientHeight;
                const scrollTop = parent.scrollTop;
            
                children.forEach(child => {
                    const childTop = child.offsetTop;
                    const childBottom = childTop + child.clientHeight;
                    let visibleHeight = Math.min(childBottom, scrollTop + parentHeight) - Math.max(childTop, scrollTop);
                    let visiblePercentage = (visibleHeight / parentHeight) * 100;
                        
                    if (visiblePercentage >= 70) {
                        let page = $(child).data("page");
                        this.currentSelectPage = page;
                        this.showPageState(page);
                    }
                });
             });
        },

        showPageState: function(page){
            if(page == 0){
                this.pageState.toggleClass("hidden-style",true);
            }else{
                this.pageState.html("Trang " + page);
                this.pageState.toggleClass("hidden-style",false);
            }
        },

        /*************** EVENT HANDLE **************/
        onMousemoveContainer: function (event) {
            let b_touch = event.touches && event.touches.length > 0;
            if (this.bMouseDown || this.bMouseMove || this.bMouseScale) {
                event.preventDefault();
                // touch and mouse
                if (b_touch) {
                    mousePositionedit = {
                        x : event.touches[0].clientX,
                        y : event.touches[0].clientY
                    };
                }else{
                    mousePositionedit = {
                        x : event.clientX,
                        y : event.clientY
                    };
                }
                // edit element: move
                if(this.currentEditElement && this.bMouseMove){
                    let newPosX = mousePositionedit.x + this.offset[0];
                    let newPosY = mousePositionedit.y + this.offset[1];
                    this.currentEditElement.style.left = newPosX + 'px';
                    this.currentEditElement.style.top  = newPosY + 'px';
                    this.updatePosElementData(this.currentEditElement.id,newPosX,newPosY);
                }
                // scale edit
                else if(this.bMouseScale && this.currentEditElement){
                    this.scaleEditElement(event,b_touch);
                }
            }
        },

        onPdfContainerMouseDown: function(event) {
            let b_touch = event.touches && event.touches.length > 0;
            this.bMouseDown = true;
            // check click cancel edit
            if(this.isClickEditArea(event)){
                this.cancelEditElement();
            }
        },
        onPdfContainerMouseLeave: function (event) {
            var element = event.target;
            if(element.id == "pdf-container"){
                if(this.bMouseMove){
                    this.bMouseMove = false;
                }
                this.bMouseDown = false;
                this.bMouseScale = false;
            }
        },

        onPdfContainerMouseUp: function (event) {
            this.bMouseMove = false;
            this.bMouseDown = false;
            this.bMouseScale = false;
        },

        onItemMouseDown: function(e,$element) {

            let b_touch = e.touches && e.touches.length > 0;
            this.bMouseDown = true;
            this.bMouseMove = true;
            this.updateEditElement($element);
        
            if(b_touch){
                this.offset = [
                    $element.position().left - e.touches[0].clientX,
                    $element.position().top - e.touches[0].clientY
                ];
            }else{
                this.offset = [
                    $element.position().left - e.clientX,
                    $element.position().top - e.clientY
                ];
            }
        },

        onItemScaleMouseDown: function(e) {
            e.stopPropagation();
            this.bMouseMove = false;
            this.bMouseDown = true;
            this.bMouseScale = true;
        
            if(this.currentEditElement){
                if(this.signData.elementID == this.currentEditElement.id){
                    this.aspectRatio = this.signData.aspectRatio;
                }
            }
        },
        elementToolAction: function (jButton) {
            let elementID = jButton.data("target-id");
            let action = jButton.data("action");
            switch (action) {
                case "delete":
                    this.deleteEditElement(elementID);
                    this.fireEvent(ON_REMOVE_SIGN,null);
                    break;
                default:
                    break;
            }
        },
        
        onPagesScroll: function(){
            const pages = this.pageList.find('.pdf-page-wrap');
            const parentHeight = this.pageList.height();
            const scrollTop = this.pageList.scrollTop();

            pages.each((_,child) => {
                const childTop = child.offsetTop;
                const childBottom = childTop + child.clientHeight;
                let visibleHeight = Math.min(childBottom, scrollTop + parentHeight) - Math.max(childTop, scrollTop);
                let visiblePercentage = (visibleHeight / parentHeight) * 100;

                if (visiblePercentage >= 70) {
                    let page = $(child).data("page");
                    this.currentSelectPage = page;
                    this.showPageState(page);
                }
            });
        },

        /************  Dom handle **************/
        showLoading(bShow){
            if(bShow){
                this.clearnPdfData();
            }
            this.pageList.toggleClass("hidden-style",bShow);
            this.pageState.toggleClass("hidden-style",bShow);
            this.pdfContainer.find(".pdf-loading").toggleClass("hidden-style",!bShow);
        },
        updatePosElementData: function(elementID,posX,posY) {
            if(this.signData.elementID == elementID){
                this.signData.pos_x = posX;
                this.signData.pos_y = posY;
            }
        },

        updatePreviewPos: function (newPosX,newPosY){
            this.previewelement.css("left",newPosX + "px");
            this.previewelement.css("top",newPosY + "px");
            this.previewelement.show();
        },

        scaleEditElement: function(event,b_touch){
            if(this.currentEditElement){
                let imageEditID = "sign-" + this.currentEditElement.id;
                let image = document.querySelector("#"+imageEditID);
                let page = $(this.currentEditElement).data("page");
                let editpage = $("#pdf-page-edit-"+page);
                var x = b_touch ? event.touches[0].pageX - editpage.offset().left : event.pageX - editpage.offset().left;
                var y = b_touch ? event.touches[0].pageY - editpage.offset().top : event.pageY - editpage.offset().top;
                const deltaX = x - this.currentEditElement.offsetLeft;
                const deltaY = y - this.currentEditElement.offsetTop;
        
                const newWidth = Math.max(deltaX, deltaY * this.aspectRatio);
                const newHeight = newWidth / this.aspectRatio;
            
                image.style.width = newWidth + 'px';
                image.style.height = newHeight + 'px';
        
                this.updateSizeElementData(this.currentEditElement.id,newWidth,newHeight);
            }
        },

        updateSizeElementData: function (elementID,width,height){
            if(this.signData.elementID == elementID){
                this.signData.width = width;
                this.signData.height = height;
            }
        },

        cancelEditElement: function () {
            if(this.currentEditElement){
                this.clearEditElementStyle(this.currentEditElement.id);
                this.currentEditElement = null;
            }
        },

        clearEditElementStyle: function (){
            let jElement = $("#"+id);
            jElement.css("z-index",1);
            jElement.toggleClass("element-selected",false);
            jElement.toggleClass("hover-edit",true);
        },

        addSignElementToPage: function(elementSource,posX,posY,pageNum) {
            
            if(this.signData){
                return;
            }

            let signatureid = elementSource.id;
            let signature_path = elementSource.src;
            let user_fullname = elementSource.getAttribute("alt");
            let id = "edit-element-sign";
            let pageEdit = $(`#pdf-page-edit-${pageNum}`);
            let imageId = "sign-" + id;
        
            let width = elementSource.width;
            let height = elementSource.height;
            let aspect_Ratio = width / height;
            let s_element = `<img data-width="${width}" data-height="${height}" style="pointer-events: none;" id="${imageId}" class="pdf-sign-image" src="${signature_path}">`;
                
            if(pageEdit.length){
                let editArea =  pageEdit.find(".pdf-page-edit-area");
                let editElement = $(`<div id="${id}" data-page="${pageNum}" style="top:${10}%;left:${10}%;user-select: none;" data-info-2="Data 2" class="pdf-edit-element element-selected">
                    <div class="pdf-edit-element-container">
                        <div class="pdf-edit-element-wrap">
                            ${s_element}
                            <div class="scale-button" data-target="${imageId}">
                                <span class="fas fa-expand" style="background: white;color:#000"></span>
                            </div>
                        </div>
                        <div class="pdf-edit-element-tool-wrap"></div>
                        </div>
                    <div style="font-family: 'Times New Roman', Times, serif;color: black;text-align: center;position: absolute;width: 100%;text-wrap: nowrap;display: flex;flex-direction: column;justify-content: center;align-items: center;font-weight: bold;margin-top: 10px;">${user_fullname}</div>
                </div>`);

                let delete_button = $(`<div class="tool-delete" data-action="delete" data-target-id="${id}">
                                            <span class="fas fa-trash-alt"></span>
                                        </div>`);
                delete_button.on('click',()=>{
                    this.elementToolAction(delete_button);
                });

                editArea.append(editElement);
                editElement.find(".pdf-edit-element-tool-wrap").append(delete_button);

                this.initEditElement(id);

                this.signData = {
                    elementID:id,
                    aspectRatio:aspect_Ratio,
                    nopage:pageNum,
                    pos_x:posX,
                    pos_y:posY,
                    signatureid:signatureid,
                    signature_path:signature_path,
                    width:width,
                    height:height,
                };
            }
        },

        renderPdfFromBlod: function(blob,pdf_sign) {
            pdf_sign.clearnPdfData();
            pdf_sign.pageList.toggleClass("hidden-style",false);
            let file = new File([blob], "filename.pdf")
            
            var fileReader = new FileReader();
            fileReader.onload = function() {
                var typedarray = new Uint8Array(this.result);
                const loadingTask = pdfjsLib.getDocument(typedarray);
                loadingTask.promise.then(pdf => {
        
                    let numpage = pdf.numPages;
                    for (let index = 1; index <= numpage; index++) {
                        pdf.getPage(index).then(function(page) {
                            pdf_sign.pageRenderList.push({page:page,index:index});
                            if(pdf_sign.pageRenderList.length == numpage){
                                pdf_sign.renderPages();
                            }
                        });
                    }
        
                });
            
            }
            fileReader.readAsArrayBuffer(file);
        },

        initEditElement: function(id) {
            let $element = $("#"+id);
            
            $element.on('mousedown touchstart',(e)=>{
                this.onItemMouseDown(e,$element);
            });

            $element.find(".scale-button").on('mousedown touchstart',(e)=>{
                this.onItemScaleMouseDown(e);
            });
        },

        updateEditElement: function($element) {
            this.currentEditElement = $element[0];
            // update style
            if(this.signData.elementID == this.currentEditElement.id){
                this.setEditElementStyle(this.currentEditElement.id);
            }else{
                this.clearEditElementStyle(this.currentEditElement.id);
            }
        },

        setEditElementStyle: function(id) {
            let $element = $("#"+id);
            $element.css("z-index",2);
            $element.toggleClass("element-selected",true);
            $element.toggleClass("hover-edit",false);
        },

        clearEditElementStyle: function(id) {
            let $element = $("#"+id);
            $element.css("z-index",1);
            $element.toggleClass("element-selected",false);
            $element.toggleClass("hover-edit",true);
        },

        renderPages: function (){
            this.pageRenderList.sort((a,b)=>{
                    if ( a.index < b.index ){
                        return -1;
                    }
                    if ( a.index > b.index ){
                        return 1;
                    }
                    return 0;
                })
            for (let i = 0; i < this.pageRenderList.length; i++) {
                let page = this.pageRenderList[i].page;
                let index = this.pageRenderList[i].index;
                this.renderPage(page,index);
            }
            this.currentSelectPage = this.pageRenderList.length > 0 ? 1 : 0;
            this.showPageState(this.currentSelectPage);
            this.pageRenderList = [];
            this.showLoading(false);
        },

        renderPage: function(page,pagenum) {
            let canvasId = this.createPageElement(pagenum);
            var canvas = document.getElementById(canvasId);
            let scale = {scale: this.default_scale};
            var viewport = page.getViewport(scale);
            var context = canvas.getContext('2d');
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            var renderContext = {
                canvasContext: context,
                viewport: viewport
            };
            var renderTask = page.render(renderContext);
        
            renderTask.promise.then(function() {
                // console.log("Render page " + pagenum);
            });
        },

        createPageElement: function(pageNum) {
            let canvasId = `canvas-pdf-page-${pageNum}`;
            this.pageList.append(`
            <div class="pdf-page-wrap" data-page="${pageNum}">
                <div id="pdf-page-${pageNum}" class="pdf-canvas">
                    <canvas id="${canvasId}" width="793" height="0"></canvas>
                </div>
                <div id="pdf-page-edit-${pageNum}" data-page="${pageNum}" class="pdf-page-edit-wrap">
                    <div class="pdf-page-edit-area" data-page="${pageNum}"></div>
                </div>
            </div>
            <div class="pdf-page-space"></div>
            `);
            return canvasId;
        },

        deleteEditElement: function(id) {
            $("#" + id).remove();
            this.signData = null;
            this.currentEditElement = null;
        },

        /*************** unit ****************/
        isClickEditArea: function (event) {
            return event.target.classList.contains('pdf-page-edit-area');
        },

        getAddElement: function(event) {
            // var element = event.target;
            // if(element.classList.contains("grap-element")){
            //     return element;
            // }
            // return null;
        },

        getSignElement: function() {
            return this.signTempElement.find(".pdf-sign-image")[0];
        },

        clearnPdfData: function() {
            this.pageList.html("");
            this.signData = null;
            this.pageRenderList = [];
        },

        validSign(sign) {
            return sign && typeof sign === 'object' && 'id' in sign && 'url' in sign;
        },

        /************* PUBLIC *************/

        loadSigndocById: function(sigdoc_id,bPreview = false){

            if(this.options.loadSigndocPath == null && this.options.loadSigndocPath == ""){
                console.warn("option loadSigndocPath không có giá trị");
                return;
            }

            this.showLoading(true);
            this.currentSigDocId = sigdoc_id;

            var pdf_sign = this;

            // load pdf
            let formdata = new FormData();
            formdata.append("authenticity_token",$('meta[name="csrf-token"]').attr("content"));
            var request = new XMLHttpRequest();
            request.responseType = 'blob';
            request.onreadystatechange = async function(){
              if(request.readyState == 4){
                if(request.status >= 200 && request.status <= 299){
                    let response = request.response;
                    if (response) {
                        if(!bPreview){
                            pdf_sign.renderPdfFromBlod(response,pdf_sign);
                            pdf_sign.fireEvent(ON_DOC_LOADED,true);
                        }else{
                            const blob = new Blob([response], { type: 'application/pdf' });
                            const url = URL.createObjectURL(blob);
                            window.open(url, '_blank');
                            pdf_sign.showLoading(false);
                        }
                    }
                }else{
                    pdf_sign.showLoading(false);
                    let response = await request.response.text();
                    console.error(response);
                    pdf_sign.fireEvent(ON_DOC_LOADED,false);
                }
              }
            };
            request.open("GET",  this.options.loadSigndocPath);
            request.send(formdata);
            return;
        },

        // load sign to pdf view
        doSign: function() {
            if(this.bReadySign){  
                alert("Văn bản đã được ký!");
                return;
            }
            let signElement = this.getSignElement();
            if(!signElement || !this.bSignExist){
                alert("Chưa có dữ liệu chữ ký!");
                return;
            }
            // scroll
            const pages = this.pageList.find('.pdf-page-wrap');

            if (pages.length == 0) {
                alert("Không thể ký vì tài liệu trống!");
                return;
            }
            const lastChild = pages[pages.length - 1];
            let posY = lastChild.offsetTop;
            let page = $(lastChild).data("page");
            this.currentSelectPage = parseInt(page) || 0;
            this.pageList.scrollTop(posY);

            this.addSignElementToPage(signElement,0,0,this.currentSelectPage);
            this.fireEvent(ON_SIGN,null);
        },

        // Load user sign data
        setUserSign: function(sign) {
            let bvalid = this.validSign(sign);
            if(bvalid){
                this.signTempElement.html(`<img id="${sign.id}" class="pdf-sign-image" src="${sign.url}" alt="${sign.user_name}" data-name="${sign.user_name}">`);
            }
            this.bSignExist = bvalid;
        },
        
        getSignData: function() {
            if(!this.signData){
                return null;
            }
            return {
                nopage: this.signData.nopage,
                px: this.signData.pos_x / this.default_scale,
                py: this.signData.pos_y / this.default_scale,
                swidth: this.signData.width / this.default_scale,
                sheight: this.signData.height / this.default_scale,
                signature_path:this.signData.signature_path,
                signatureid:this.signData.signatureid,
            }
        },

        setSignStatus: function(signed) {
            this.bReadySign = signed;
        },

        on: function(eventName, callback) {
            this.events[eventName] = this.events[eventName] || [];
            this.events[eventName].push(callback);
        },

        fireEvent: function(eventName,...args) {
            if (this.events[eventName]) {
                this.events[eventName].forEach(callback => callback(...args));
            }
        }
        
    }

    $.fn.pdfSign = function(options) {
        if (this.length === 1) {
            return new pdfSign(this[0], options).init();
        }
        return Array.from(this).map(el => new pdfSign(el, options).init());
    };
})(jQuery)